import{_ as a,o as r,c as l,ae as e}from"./chunks/framework.DD8idMxO.js";const g=JSON.parse('{"title":"AgentSkillOS","description":"","frontmatter":{},"headers":[],"relativePath":"radar/tech-agentskillos.md","filePath":"radar/tech-agentskillos.md"}'),o={name:"radar/tech-agentskillos.md"};function i(n,t,s,d,h,u){return r(),l("div",null,[...t[0]||(t[0]=[e('<h1 id="agentskillos" tabindex="-1">AgentSkillOS <a class="header-anchor" href="#agentskillos" aria-label="Permalink to &quot;AgentSkillOS&quot;">​</a></h1><blockquote><p><strong>分类</strong>: Skill 召回 / Skill 执行 / Skill 管理 | <strong>成熟度</strong>: 🟡 成长期 | <strong>综合评分</strong>: 0.51</p></blockquote><hr><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><p><strong>一句话描述</strong>: 把数十万 Skill 组织成 <strong>Capability Tree + DAG 编排</strong>的&quot;操作系统级&quot;基础设施。</p><p><strong>来源</strong>:</p><ul><li>学术研究</li></ul><p><strong>链接</strong>:</p><ul><li>论文：<a href="https://arxiv.org/abs/2603.02176" target="_blank" rel="noreferrer">arXiv 2603.02176</a></li></ul><hr><h2 id="核心技术" tabindex="-1">核心技术 <a class="header-anchor" href="#核心技术" aria-label="Permalink to &quot;核心技术&quot;">​</a></h2><h3 id="capability-tree-递归分类" tabindex="-1">Capability Tree 递归分类 <a class="header-anchor" href="#capability-tree-递归分类" aria-label="Permalink to &quot;Capability Tree 递归分类&quot;">​</a></h3><p>把数十万 Skill 组织成一棵能力树：节点是能力类别，叶子是具体 Skill。用户提任务时，系统从树根递归定位到最相关 Skill 子集。</p><p>对比线性搜索全部 Skill，<strong>树状检索在 200 - 200K 规模上都接近理想准确率</strong>。</p><h3 id="dag-编排-核心创新" tabindex="-1">DAG 编排（核心创新） <a class="header-anchor" href="#dag-编排-核心创新" aria-label="Permalink to &quot;DAG 编排（核心创新）&quot;">​</a></h3><p>识别任务中的 Skill 依赖关系，构建 <strong>有向无环图</strong>：</p><ul><li>能并行的步骤并行执行（如&quot;抓取数据&quot; + &quot;准备 PPT 模板&quot;）</li><li>必须串行的按序执行（如&quot;清洗数据&quot;必须等&quot;抓取&quot;完成）</li></ul><p>DAG 执行<strong>显著优于</strong>简单逐个调用。</p><h3 id="基准" tabindex="-1">基准 <a class="header-anchor" href="#基准" aria-label="Permalink to &quot;基准&quot;">​</a></h3><p>30 个 artifact-rich 任务基准，覆盖：</p><ul><li>数据计算 / 文档创建 / 动态视频 / 视觉设计 / Web 交互</li></ul><hr><h2 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to &quot;技术细节&quot;">​</a></h2><h3 id="局限性" tabindex="-1">局限性 <a class="header-anchor" href="#局限性" aria-label="Permalink to &quot;局限性&quot;">​</a></h3><ul><li>DAG 编排假设 Skill 依赖关系<strong>可在执行前静态确定</strong> —— 动态依赖场景（&quot;第二步选择取决于第一步结果&quot;）未覆盖</li><li>不涉及 Skill 进化或安全治理</li><li>仅学术验证，未产品化</li></ul><hr><h2 id="成熟度评分" tabindex="-1">成熟度评分 <a class="header-anchor" href="#成熟度评分" aria-label="Permalink to &quot;成熟度评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>评分</th><th>说明</th></tr></thead><tbody><tr><td>技术成熟度</td><td>0.55</td><td>论文阶段，工具未开源</td></tr><tr><td>创新性</td><td>0.75</td><td>Capability Tree + DAG 是开创性架构</td></tr><tr><td>落地程度</td><td>0.35</td><td>学术</td></tr><tr><td>生态活跃度</td><td>0.35</td><td>较少</td></tr></tbody></table><p><strong>综合评分</strong>: <strong>0.51</strong></p><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2603.02176" target="_blank" rel="noreferrer">AgentSkillOS 论文</a></li></ul>',32)])])}const p=a(o,[["render",i]]);export{g as __pageData,p as default};
